package tn.esprit.controllers;

import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.fxml.FXML;
import javafx.fxml.FXMLLoader;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.VBox;
import javafx.scene.layout.ScrollPane;
import javafx.stage.Stage;
import tn.esprit.entities.User;
import tn.esprit.services.UserService;

import java.io.IOException;
import java.util.List;
import java.util.Optional;
import java.util.regex.Pattern;

public class AdminDashboardController {
    @FXML private TableView<User> usersTable;
    @FXML private TableColumn<User, Integer> idColumn;
    @FXML private TableColumn<User, String> nameColumn;
    @FXML private TableColumn<User, String> emailColumn;
    @FXML private TableColumn<User, String> roleColumn;
    @FXML private TextField searchField;
    @FXML private Label welcomeLabel;

    private UserService userService = new UserService();
    private User loggedInUser;
    private ObservableList<User> usersList = FXCollections.observableArrayList();

    @FXML
    public void initialize() {
        setupTableColumns();
        loadUsers();

        // Add listener to search field
        searchField.textProperty().addListener((obs, oldVal, newVal) -> {
            if (newVal == null || newVal.isEmpty()) {
                loadUsers();
            } else {
                searchUsers(newVal);
            }
        });
    }

    private void setupTableColumns() {
        idColumn.setCellValueFactory(cellData -> new javafx.beans.property.SimpleIntegerProperty(cellData.getValue().getId()).asObject());
        nameColumn.setCellValueFactory(cellData -> new javafx.beans.property.SimpleStringProperty(
                cellData.getValue().getFullName() != null ? cellData.getValue().getFullName() : ""
        ));
        emailColumn.setCellValueFactory(cellData -> new javafx.beans.property.SimpleStringProperty(cellData.getValue().getEmail()));
        roleColumn.setCellValueFactory(cellData -> new javafx.beans.property.SimpleStringProperty(cellData.getValue().getRole()));
    }

    private void loadUsers() {
        List<User> users = userService.getAllUsers();
        usersList = FXCollections.observableArrayList(users);
        usersTable.setItems(usersList);
    }

    private void searchUsers(String searchTerm) {
        List<User> results = userService.searchUsers(searchTerm);
        usersList = FXCollections.observableArrayList(results);
        usersTable.setItems(usersList);
    }

    public void handleAddUser() {
        Dialog<User> dialog = new Dialog<>();
        dialog.setTitle("Add User");
        dialog.setHeaderText("Add New User");

        TextField firstNameField = new TextField();
        firstNameField.setPromptText("First Name");
        TextField lastNameField = new TextField();
        lastNameField.setPromptText("Last Name");
        TextField emailField = new TextField();
        emailField.setPromptText("Email");
        PasswordField passwordField = new PasswordField();
        passwordField.setPromptText("Password");
        ComboBox<String> roleCombo = new ComboBox<>();
        roleCombo.setItems(FXCollections.observableArrayList("admin", "doctor", "user"));
        roleCombo.setValue("user");
        TextField specialityField = new TextField();
        specialityField.setPromptText("Speciality (for doctors)");
        TextField phoneField = new TextField();
        phoneField.setPromptText("Phone (for users)");
        TextField addressField = new TextField();
        addressField.setPromptText("Address (for users)");

        VBox content = new VBox(10);
        content.setStyle("-fx-padding: 10;");
        content.getChildren().addAll(
                new Label("First Name:"), firstNameField,
                new Label("Last Name:"), lastNameField,
                new Label("Email:"), emailField,
                new Label("Password:"), passwordField,
                new Label("Role:"), roleCombo,
                new Label("Speciality (for doctors):"), specialityField,
                new Label("Phone (for users):"), phoneField,
                new Label("Address (for users):"), addressField
        );

        ScrollPane scrollPane = new ScrollPane(content);
        dialog.getDialogPane().setContent(scrollPane);

        ButtonType addButtonType = new ButtonType("Add", ButtonBar.ButtonData.OK_DONE);
        dialog.getDialogPane().getButtonTypes().addAll(addButtonType, ButtonType.CANCEL);

        dialog.setResultConverter(dialogButton -> {
            if (dialogButton == addButtonType) {
                String firstName = firstNameField.getText().trim();
                String lastName = lastNameField.getText().trim();
                String email = emailField.getText().trim();
                String password = passwordField.getText();
                String role = roleCombo.getValue();

                if (firstName.isEmpty() || lastName.isEmpty() || email.isEmpty() || password.isEmpty()) {
                    showAlert("Error", "All fields are required", Alert.AlertType.ERROR);
                    return null;
                }

                if (!isValidEmail(email)) {
                    showAlert("Error", "Invalid email format", Alert.AlertType.ERROR);
                    return null;
                }

                if (password.length() < 6) {
                    showAlert("Error", "Password must be at least 6 characters", Alert.AlertType.ERROR);
                    return null;
                }

                if (userService.emailExists(email)) {
                    showAlert("Error", "Email already exists", Alert.AlertType.ERROR);
                    return null;
                }

                User newUser = new User();
                newUser.setFirstName(firstName);
                newUser.setLastName(lastName);
                newUser.setFullName(firstName + " " + lastName);
                newUser.setEmail(email);
                newUser.setPassword(password);
                newUser.setRole(role);
                if (!specialityField.getText().isEmpty()) {
                    newUser.setSpeciality(specialityField.getText().trim());
                }
                if (!phoneField.getText().isEmpty()) {
                    newUser.setPhone(phoneField.getText().trim());
                }
                if (!addressField.getText().isEmpty()) {
                    newUser.setAddress(addressField.getText().trim());
                }

                return newUser;
            }
            return null;
        });

        Optional<User> result = dialog.showAndWait();
        if (result.isPresent()) {
            User newUser = result.get();
            if (userService.addUser(newUser, newUser.getRole())) {
                showAlert("Success", "User added successfully", Alert.AlertType.INFORMATION);
                loadUsers();
            } else {
                showAlert("Error", "Failed to add user", Alert.AlertType.ERROR);
            }
        }
    }

    public void handleEditUser() {
        User selectedUser = usersTable.getSelectionModel().getSelectedItem();
        if (selectedUser == null) {
            showAlert("Warning", "Please select a user to edit", Alert.AlertType.WARNING);
            return;
        }

        Dialog<User> dialog = new Dialog<>();
        dialog.setTitle("Edit User");
        dialog.setHeaderText("Edit User Details");

        TextField firstNameField = new TextField(selectedUser.getFirstName() != null ? selectedUser.getFirstName() : "");
        TextField lastNameField = new TextField(selectedUser.getLastName() != null ? selectedUser.getLastName() : "");
        TextField emailField = new TextField(selectedUser.getEmail());
        PasswordField passwordField = new PasswordField();
        passwordField.setText(selectedUser.getPassword());
        TextField specialityField = new TextField(selectedUser.getSpeciality() != null ? selectedUser.getSpeciality() : "");
        TextField phoneField = new TextField(selectedUser.getPhone() != null ? selectedUser.getPhone() : "");
        TextField addressField = new TextField(selectedUser.getAddress() != null ? selectedUser.getAddress() : "");

        VBox content = new VBox(10);
        content.setStyle("-fx-padding: 10;");
        content.getChildren().addAll(
                new Label("First Name:"), firstNameField,
                new Label("Last Name:"), lastNameField,
                new Label("Email:"), emailField,
                new Label("Password:"), passwordField,
                new Label("Speciality (for doctors):"), specialityField,
                new Label("Phone (for users):"), phoneField,
                new Label("Address (for users):"), addressField
        );

        ScrollPane scrollPane = new ScrollPane(content);
        dialog.getDialogPane().setContent(scrollPane);

        ButtonType updateButtonType = new ButtonType("Update", ButtonBar.ButtonData.OK_DONE);
        dialog.getDialogPane().getButtonTypes().addAll(updateButtonType, ButtonType.CANCEL);

        dialog.setResultConverter(dialogButton -> {
            if (dialogButton == updateButtonType) {
                String firstName = firstNameField.getText().trim();
                String lastName = lastNameField.getText().trim();
                String email = emailField.getText().trim();
                String password = passwordField.getText();

                if (firstName.isEmpty() || lastName.isEmpty() || email.isEmpty() || password.isEmpty()) {
                    showAlert("Error", "All fields are required", Alert.AlertType.ERROR);
                    return null;
                }

                if (!isValidEmail(email)) {
                    showAlert("Error", "Invalid email format", Alert.AlertType.ERROR);
                    return null;
                }

                if (userService.emailExistsExcludingId(email, selectedUser.getId())) {
                    showAlert("Error", "Email already exists", Alert.AlertType.ERROR);
                    return null;
                }

                selectedUser.setFirstName(firstName);
                selectedUser.setLastName(lastName);
                selectedUser.setFullName(firstName + " " + lastName);
                selectedUser.setEmail(email);
                selectedUser.setPassword(password);
                if (!specialityField.getText().isEmpty()) {
                    selectedUser.setSpeciality(specialityField.getText().trim());
                }
                if (!phoneField.getText().isEmpty()) {
                    selectedUser.setPhone(phoneField.getText().trim());
                }
                if (!addressField.getText().isEmpty()) {
                    selectedUser.setAddress(addressField.getText().trim());
                }

                return selectedUser;
            }
            return null;
        });

        Optional<User> result = dialog.showAndWait();
        if (result.isPresent()) {
            User updatedUser = result.get();
            if (userService.updateUser(updatedUser, updatedUser.getRole())) {
                showAlert("Success", "User updated successfully", Alert.AlertType.INFORMATION);
                loadUsers();
            } else {
                showAlert("Error", "Failed to update user", Alert.AlertType.ERROR);
            }
        }
    }

    public void handleDeleteUser() {
        User selectedUser = usersTable.getSelectionModel().getSelectedItem();
        if (selectedUser == null) {
            showAlert("Warning", "Please select a user to delete", Alert.AlertType.WARNING);
            return;
        }

        if (selectedUser.getRole().equals("doctor")) {
            showAlert("Info", "Doctor deletion is optional and not allowed in this version", Alert.AlertType.INFORMATION);
            return;
        }

        Alert confirmAlert = new Alert(Alert.AlertType.CONFIRMATION);
        confirmAlert.setTitle("Confirm Delete");
        confirmAlert.setHeaderText("Delete User");
        confirmAlert.setContentText("Are you sure you want to delete this user?");

        Optional<ButtonType> result = confirmAlert.showAndWait();
        if (result.isPresent() && result.get() == ButtonType.OK) {
            if (userService.deleteUser(selectedUser.getId(), selectedUser.getRole())) {
                showAlert("Success", "User deleted successfully", Alert.AlertType.INFORMATION);
                loadUsers();
            } else {
                showAlert("Error", "Failed to delete user", Alert.AlertType.ERROR);
            }
        }
    }

    public void handleLogout() {
        try {
            FXMLLoader loader = new FXMLLoader(getClass().getResource("/fxml/login.fxml"));
            Scene scene = new Scene(loader.load());
            scene.getStylesheets().add(getClass().getResource("/css/style.css").toExternalForm());

            Stage stage = (Stage) usersTable.getScene().getWindow();
            stage.setScene(scene);
            stage.setTitle("Login");
            stage.show();
        } catch (IOException e) {
            showAlert("Error", "Failed to load login page", Alert.AlertType.ERROR);
            e.printStackTrace();
        }
    }

    private boolean isValidEmail(String email) {
        String emailRegex = "^[A-Za-z0-9+_.-]+@(.+)$";
        Pattern pattern = Pattern.compile(emailRegex);
        return pattern.matcher(email).matches();
    }

    private void showAlert(String title, String message, Alert.AlertType type) {
        Alert alert = new Alert(type);
        alert.setTitle(title);
        alert.setContentText(message);
        alert.showAndWait();
    }

    public void setLoggedInUser(User user) {
        this.loggedInUser = user;
        welcomeLabel.setText("Welcome, " + user.getFullName() + " (Admin)");
    }
}

